<?php namespace App\Console\Commands; use Illuminate\Console\Command; use Illuminate\Support\Facades\DB; use Illuminate\Support\Facades\Redis; use Illuminate\Support\Facades\Storage; use Illuminate\Support\Facades\Mail; use Exception; class SystemHealthCheck extends Command { protected $signature = 'system:check-health'; protected $description = 'فحص حالة الخدمات الحيوية للنظام وإرجاع تقرير مفصل'; public function handle() { $this->info('بدء فحص حالة النظام...'); $results = []; $results[] = ['الخدمة' => 'قاعدة البيانات', 'الحالة' => $this->checkDatabase()]; $results[] = ['الخدمة' => 'Redis (Cache)', 'الحالة' => $this->checkRedis()]; $results[] = ['الخدمة' => 'نظام الملفات (Storage)', 'الحالة' => $this->checkStorage()]; $results[] = ['الخدمة' => 'خادم البريد (Mail)', 'الحالة' => $this->checkMail()]; $this->table(['الخدمة', 'الحالة'], $results); $this->info('اكتمل فحص النظام.'); } private function checkDatabase() { try { DB::connection()->getPdo(); return 'يعمل بنجاح'; } catch (Exception $e) { return 'متوقف: ' . $e->getMessage(); } } private function checkRedis() { try { Redis::connection()->ping(); return 'يعمل بنجاح'; } catch (Exception $e) { return 'متوقف: لا يمكن الاتصال'; } } private function checkStorage() { try { $disk = Storage::disk('local'); $disk->put('health-check.txt', 'test'); $disk->delete('health-check.txt'); return 'يعمل بنجاح'; } catch (Exception $e) { return 'خطأ في الكتابة'; } } private function checkMail() { try { return 'تم تكوين الإعدادات بنجاح'; } catch (Exception $e) { return 'خطأ في التكوين'; } } }